1	`include "common_defs.v"
2	
3	module rotate
4	(
5	    input clock,
6	    input enable,
7	    input reset,
8	
9	    input [15:0] in_i,
10	    input [15:0] in_q,
11	    // [-PI, PI]
12	    // scaled up by ATAN_LUT_SCALE_SHIFT
13	    input signed [31:0] phase,
14	    input input_strobe,
15	
16	    output [`ROTATE_LUT_LEN_SHIFT-1:0] rot_addr,
17	    input [31:0] rot_data,
18	
19	    output signed [15:0] out_i,
20	    output signed [15:0] out_q,
21	    output output_strobe
22	);
23	`include "common_params.v"
24	
25	reg [31:0] phase_delayed;
26	reg [31:0] phase_abs;
27	
28	reg [2:0] quadrant;
29	reg [2:0] quadrant_delayed;
30	wire [15:0] in_i_delayed;
31	wire [15:0] in_q_delayed;
32	
33	reg [31:0] actual_phase;
34	
35	wire [15:0] raw_rot_i;
36	wire [15:0] raw_rot_q;
37	reg [15:0] rot_i;
38	reg [15:0] rot_q;
39	
40	wire mult_in_stb;
41	
42	wire [31:0] p_i;
43	wire [31:0] p_q;
44	
45	assign out_i = p_i[`ROTATE_LUT_SCALE_SHIFT+15:`ROTATE_LUT_SCALE_SHIFT];
46	assign out_q = p_q[`ROTATE_LUT_SCALE_SHIFT+15:`ROTATE_LUT_SCALE_SHIFT];
47	
48	assign rot_addr = actual_phase[`ROTATE_LUT_LEN_SHIFT-1:0];
49	assign raw_rot_i = rot_data[31:16];
50	assign raw_rot_q = rot_data[15:0];
51	
52	
53	delayT #(.DATA_WIDTH(32), .DELAY(4)) in_delay_inst (
54	    .clock(clock),
55	    .reset(reset),
56	
57	    .data_in({in_i, in_q}),
58	    .data_out({in_i_delayed, in_q_delayed})
59	);
60	
61	delayT #(.DATA_WIDTH(1), .DELAY(4)) mult_delay_inst (
62	    .clock(clock),
63	    .reset(reset),
64	
65	    .data_in(input_strobe),
66	    .data_out(mult_in_stb)
67	);
68	
69	
70	complex_mult mult_inst (
71	    .clock(clock),
72	    .enable(enable),
73	    .reset(reset),
74	    .a_i(in_i_delayed),
75	    .a_q(in_q_delayed),
76	    .b_i(rot_i),
77	    .b_q(rot_q),
78	    .input_strobe(mult_in_stb),
79	    .p_i(p_i),
80	    .p_q(p_q),
81	    .output_strobe(output_strobe)
82	);
83	
84	
85	integer i;
86	always @(posedge clock) begin
87	    if (reset) begin
88	        actual_phase <= 0;
89	
90	        rot_i <= 0;
91	        rot_q <= 0;
92	        phase_abs <= 0;
93	        phase_delayed <= 0;
94	
95	    end else if (enable) begin
96	        `ifdef DEBUG_PRINT
97	            if (phase > PI || phase < -PI) begin
98	                $display("[WARN] phase overflow: %d\n", phase);
99	            end
100	        `endif
101	
102	        // cycle 1
103	        phase_abs <= phase[31]? ~phase+1: phase;
104	        phase_delayed <= phase;
105	
106	        // cycle 2
107	        if (phase_abs <= PI_4) begin
108	            quadrant <= {phase_delayed[31], 2'b00};
109	            actual_phase <= phase_abs;
110	        end else if (phase_abs <= PI_2) begin
111	            quadrant <= {phase_delayed[31], 2'b01};
112	            actual_phase <= PI_2 - phase_abs;
113	        end else if (phase_abs <= PI_3_4) begin
114	            quadrant <= {phase_delayed[31], 2'b10};
115	            actual_phase <= phase_abs - PI_2;
116	        end else begin
117	            quadrant <= {phase_delayed[31], 2'b11};
118	            actual_phase <= PI - phase_abs;
119	        end
120	
121	        // cycle 3
122	        // wait for raw_rot_i
123	        quadrant_delayed <= quadrant;
124	
125	        // cycle 4
126	        case(quadrant_delayed)
127	            3'b000: begin
128	                rot_i <= raw_rot_i;
129	                rot_q <= raw_rot_q;
130	            end
131	            3'b001: begin
132	                rot_i <= raw_rot_q;
133	                rot_q <= raw_rot_i;
134	            end
135	            3'b010: begin
136	                rot_i <= ~raw_rot_q+1;
137	                rot_q <= raw_rot_i;
138	            end
139	            3'b011: begin
140	                rot_i <= ~raw_rot_i+1;
141	                rot_q <= raw_rot_q;
142	            end
143	            3'b100: begin
144	                rot_i <= raw_rot_i;
145	                rot_q <= ~raw_rot_q+1;
146	            end
147	            3'b101: begin
148	                rot_i <= raw_rot_q;
149	                rot_q <= ~raw_rot_i+1;
150	            end
151	            3'b110: begin
152	                rot_i <= ~raw_rot_q+1;
153	                rot_q <= ~raw_rot_i+1;
154	            end
155	            3'b111: begin
156	                rot_i <= ~raw_rot_i+1;
157	                rot_q <= ~raw_rot_q+1;
158	            end
159	        endcase
160	    end
161	end
162	
163	endmodule
